1076	main (int argc, char **argv) {
1077	     int status = 0;
1078	     char *nextarg;
1079	     char *tmp;
1080	     char *section = 0;
1081	
1082	#ifdef __CYGWIN32__
1083	     extern int optind;
1084	#endif
